488→func collectOpenAIReasoningTexts(node gjson.Result) []string {
489→	var texts []string
490→	if !node.Exists() {
491→		return texts
492→	}
493→
494→	if node.IsArray() {
495→		node.ForEach(func(_, value gjson.Result) bool {
496→			texts = append(texts, collectOpenAIReasoningTexts(value)...)
497→			return true
498→		})
499→		return texts
500→	}
501→
502→	switch node.Type {
503→	case gjson.String:
504→		if text := node.String(); text != "" {
505→			texts = append(texts, text)
506→		}
507→	case gjson.JSON:
508→		if text := node.Get("text"); text.Exists() {
509→			if textStr := text.String(); textStr != "" {
510→				texts = append(texts, textStr)
511→			}
512→		} else if raw := node.Raw; raw != "" && !strings.HasPrefix(raw, "{") && !strings.HasPrefix(raw, "[") {
513→			texts = append(texts, raw)
514→		}
515→	}
516→
517→	return texts
518→}
