func TestConvertCodexResponseToClaude_ClaudeCLIToolProgressTextEmittedOnCategoryTransition(t *testing.T) {
	readAdded := []byte(`data: {"type":"response.output_item.added","item":{"type":"function_call","call_id":"call_read","name":"Read"},"output_index":0,"sequence_number":1}`)
	readAdded2 := []byte(`data: {"type":"response.output_item.added","item":{"type":"function_call","call_id":"call_read2","name":"Read"},"output_index":1,"sequence_number":2}`)
	bashAdded := []byte(`data: {"type":"response.output_item.added","item":{"type":"function_call","call_id":"call_bash","name":"Bash"},"output_index":2,"sequence_number":3}`)

	var param any
	first := ConvertCodexResponseToClaude(claudeCLICtx(), "gpt-5.4", nil, nil, readAdded, &param)
	if len(first) != 1 {
		t.Fatalf("expected 1 first output chunk, got %d", len(first))
	}
	firstChunk := string(first[0])
	if !strings.Contains(firstChunk, "Reading relevant files.") {
		t.Fatalf("expected first read call to emit progress text, got %q", firstChunk)
	}
	if !strings.Contains(firstChunk, "\"type\":\"tool_use\"") {
		t.Fatalf("expected read call to still emit tool_use, got %q", firstChunk)
	}

	second := ConvertCodexResponseToClaude(claudeCLICtx(), "gpt-5.4", nil, nil, readAdded2, &param)
	if len(second) != 1 {
		t.Fatalf("expected 1 second output chunk, got %d", len(second))
	}
	if strings.Contains(string(second[0]), "Reading relevant files.") {
		t.Fatalf("expected repeated read category to skip duplicate progress text, got %q", string(second[0]))
	}

	third := ConvertCodexResponseToClaude(claudeCLICtx(), "gpt-5.4", nil, nil, bashAdded, &param)
	if len(third) != 1 {
		t.Fatalf("expected 1 third output chunk, got %d", len(third))
	}
	thirdChunk := string(third[0])
	if !strings.Contains(thirdChunk, "Running a verification command.") {
		t.Fatalf("expected bash call to emit category transition progress text, got %q", thirdChunk)
	}
	if !strings.Contains(thirdChunk, "\"name\":\"Bash\"") {
		t.Fatalf("expected bash tool_use to remain intact, got %q", thirdChunk)
	}
}

